#include<bits/stdc++.h>
using namespace std;
using namespace std;
int dis[2001],f[2001][2001];
int n,m;
int t[2001];
int main()
{
    memset(f,0x3f,sizeof(f));
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&t[i]);
        f[i][i]=0;
    }
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        u++;
        v++;
        f[u][v]=f[v][u]=min(f[u][v],w);
    }
    int q;
    scanf("%d",&q);
    int k=1;
    while(q--)
    {
        int x,y,tim;
        scanf("%d%d%d",&x,&y,&tim);
        x++;
        y++;
        if(t[x]>tim||t[y]>tim)
        {
            printf("-1\n");
            continue;
        }
        while(k<=n&&t[k]<=tim)
        {
            for(int i=1;i<=n;i++)
            {
                for(int j=1;j<=n;j++)
                {
                    f[i][j]=min(f[i][j],f[i][k]+f[k][j]);
                }
            }
            k++;
        }
        if(f[x][y]==0x3f3f3f3f)
        {
            printf("-1\n");
        }
        else
        {
            printf("%d\n",f[x][y]);
        }
    }
    return 0;
}
